{
  "lessons": [
    {
      "description": "Trace why recurrent and convolutional sequence models struggled with long-range dependencies and slow step-by-step computation. See how the Transformer made sequence processing more parallel by letting every position directly attend to every other position.",
      "title": "Why attention replaced recurrence"
    },
    {
      "description": "Turn text, image patches, or audio frames into vectors a transformer can process. Reason through how embeddings carry content while positional information tells the model where each item sits in the sequence.",
      "title": "Making tokens and positions visible"
    },
    {
      "description": "Follow the query-key-value calculation behind scaled dot-product attention. Compute which tokens matter most to one position and how their value vectors are blended into a new representation.",
      "title": "Computing attention with Q, K, and V"
    },
    {
      "description": "Trace self-attention across a short sentence to see how each word’s representation changes after looking at the rest of the sequence. Recognize why the same mechanism can connect nearby words, distant words, and repeated references.",
      "title": "Building context with self-attention"
    },
    {
      "description": "Use attention masks to control what a model is allowed to see. Compare padding masks that ignore empty positions with causal masks that prevent a decoder from peeking at future tokens.",
      "title": "Controlling attention with masks"
    },
    {
      "description": "Reason through why transformers run several attention heads in parallel instead of one giant attention calculation. See how different heads can specialize in different relationships, such as syntax, position, or topic links.",
      "title": "Splitting focus with multi-head attention"
    },
    {
      "description": "Follow the non-attention pieces inside a transformer block: feed-forward layers, residual connections, layer normalization, and dropout. See how they stabilize training and add nonlinear computation after attention mixes information.",
      "title": "Inside a transformer block"
    },
    {
      "description": "Stack encoder blocks to turn an input sequence into contextual representations for every token. Connect this encoder-only pattern to classification, tagging, retrieval embeddings, and bidirectional understanding tasks.",
      "title": "Reading inputs with encoder stacks"
    },
    {
      "description": "Trace how a decoder generates one token at a time using masked self-attention. See why decoder-only transformers are natural for next-token prediction and open-ended text generation.",
      "title": "Generating tokens with decoder stacks"
    },
    {
      "description": "Follow cross-attention in an encoder-decoder transformer, where the decoder attends to encoder outputs while producing a target sequence. Use translation or summarization to see why this design separates reading the source from writing the output.",
      "title": "Connecting encoder and decoder with cross-attention"
    },
    {
      "description": "Compare encoder-only, decoder-only, and encoder-decoder transformers by what they can see and what they are trained to produce. Place BERT, GPT, and T5 into the right architectural families without treating them as interchangeable.",
      "title": "Sorting BERT, GPT, and T5"
    },
    {
      "description": "Work through masked language modeling, where some input tokens are hidden and the model predicts them from both left and right context. See why BERT-style pretraining produces strong representations for understanding tasks.",
      "title": "Pretraining BERT with masked tokens"
    },
    {
      "description": "Work through causal language modeling, where each token is predicted from earlier tokens only. See how this objective trains GPT-style decoders to continue sequences while respecting the same masking used during generation.",
      "title": "Pretraining GPT with next-token prediction"
    },
    {
      "description": "Trace sequence-to-sequence denoising, where corrupted input text is reconstructed by an encoder-decoder model. Connect this pattern to T5-style pretraining and tasks that naturally map one sequence into another.",
      "title": "Pretraining T5 by repairing text"
    },
    {
      "description": "Reason through fine-tuning a pretrained transformer by adding a small task head or training the whole model on labeled examples. Compare classification, token labeling, and sequence generation as different ways to reuse the same pretrained backbone.",
      "title": "Adapting transformers to supervised tasks"
    },
    {
      "description": "Recognize why full self-attention grows quadratically with sequence length. Compare common responses such as shorter windows, sparse attention, linear attention ideas, and memory-efficient kernels like FlashAttention.",
      "title": "Managing the cost of long sequences"
    },
    {
      "description": "Turn an image into a sequence of patches and process it with a transformer. See how Vision Transformers such as ViT use patch embeddings, position embeddings, and often a classification token instead of convolutional feature maps.",
      "title": "Treating image patches as tokens"
    },
    {
      "description": "Trace how transformers handle audio as frames, spectrogram patches, or learned speech representations. Connect models such as wav2vec 2.0 to the same attention machinery used for language, with different input features and training signals.",
      "title": "Applying transformers to audio"
    },
    {
      "description": "Compare two common multimodal transformer patterns: sharing one token sequence across modalities and using cross-attention between separate streams. Place CLIP-style contrastive pretraining and image-text models in this design space.",
      "title": "Linking modalities with attention"
    }
  ]
}
